package service

import (
	"context"
	"fmt"
	"os"

	"github.com/google/generative-ai-go/genai"
	"github.com/pgvector/pgvector-go"
	"google.golang.org/api/option"
)

// EmbeddingService converts a description into a vector representation using Gemini.
type EmbeddingService struct {
	client *genai.Client
}

func NewEmbeddingService() *EmbeddingService {
	apiKey := os.Getenv("GEMINI_API_KEY")
	ctx := context.Background()
	client, err := genai.NewClient(ctx, option.WithAPIKey(apiKey))
	if err != nil {
		fmt.Printf("Failed to create Gemini client: %v\n", err)
		return nil
	}
	return &EmbeddingService{
		client: client,
	}
}

func (s *EmbeddingService) EmbedDescription(ctx context.Context, description string) (pgvector.Vector, error) {
	modelName := os.Getenv("GEMINI_MODEL")
	if modelName == "" {
		modelName = "gemini-embedding-2"
	}

	model := s.client.EmbeddingModel(modelName)

	res, err := model.EmbedContent(ctx, genai.Text(description))
	if err != nil {
		return pgvector.Vector{}, fmt.Errorf("gemini embedding failed: %w", err)
	}

	return pgvector.NewVector(res.Embedding.Values), nil
}

func (s *EmbeddingService) EmbedFruit(ctx context.Context, f *model.Fruit) (pgvector.Vector, error) {
	description := fmt.Sprintf("A %s fruit from %s. Best for %s. It has a %s texture and a %s flavor profile.", f.Name, f.Origin, f.BestFor, f.Texture, f.Flavor)
	return s.EmbedDescription(ctx, description)
}

package service

import (
	"context"
	"fmt"
	"os"

	"github.com/google/generative-ai-go/genai"
	"github.com/pgvector/pgvector-go"
	"google.golang.org/api/option"
)

// EmbeddingService converts a description into a vector representation using Gemini.
type EmbeddingService struct {
	client *genai.Client
}

func NewEmbeddingService() *EmbeddingService {
	apiKey := os.Getenv("GEMINI_API_KEY")
	ctx := context.Background()
	client, err := genai.NewClient(ctx, option.WithAPIKey(apiKey))
	if err != nil {
		fmt.Printf("Failed to create Gemini client: %v\n", err)
		return nil
	}
	return &EmbeddingService{
		client: client,
	}
}

func (s *EmbeddingService) EmbedDescription(ctx context.Context, description string) (pgvector.Vector, error) {
	modelName := os.Getenv("GEMINI_MODEL")
	if modelName == "" {
		modelName = "gemini-embedding-2"
	}

	model := s.client.EmbeddingModel(modelName)

	res, err := model.EmbedContent(ctx, genai.Text(description))
	if err != nil {
		return pgvector.Vector{}, fmt.Errorf("gemini embedding failed: %w", err)
	}

	return pgvector.NewVector(res.Embedding.Values), nil
}

func (s *EmbeddingService) EmbedFruit(ctx context.Context, f *model.Fruit) (pgvector.Vector, error) {
	description := fmt.Sprintf("A %s fruit from %s, available during %s. Best for %s. It has a %s texture and a %s flavor profile.", f.Name, f.Origin, f.Season, f.BestFor, f.Texture, f.Flavor)
	return s.EmbedDescription(ctx, description)
}

package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os/signal"
	"syscall"
	"time"

	"vector-search-project/internal/server"

	"github.com/joho/godotenv"
)

func gracefulShutdown(apiServer *http.Server, done chan bool) {
	// Create context that listens for the interrupt signal from the OS.
	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	// Listen for the interrupt signal.
	<-ctx.Done()

	log.Println("shutting down gracefully, press Ctrl+C again to force")
	stop() // Allow Ctrl+C to force shutdown

	// The context is used to inform the server it has 5 seconds to finish
	// the request it is currently handling
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := apiServer.Shutdown(ctx); err != nil {
		log.Printf("Server forced to shutdown with error: %v", err)
	}

	log.Println("Server exiting")

	// Notify the main goroutine that the shutdown is complete
	done <- true
}

func main() {
	if err := godotenv.Load(); err != nil {
		log.Println("No .env file found, using defaults")
	}

	apiServer := server.NewServer()

	// Create a done channel to signal when the shutdown is complete
	done := make(chan bool, 1)

	// Run graceful shutdown in a separate goroutine
	go gracefulShutdown(apiServer, done)

	fmt.Printf("Server starting on http://localhost%s\n", apiServer.Addr)
	fmt.Printf("Example query: http://localhost%s/search?q=sweet+yellow+fruit\n", apiServer.Addr)

	err := apiServer.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		panic(fmt.Sprintf("http server error: %s", err))
	}

	// Wait for the graceful shutdown to complete
	<-done
	log.Println("Graceful shutdown complete.")
}

package main

import (
	"context"
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"vector-search-project/internal/server"

	"github.com/joho/godotenv"
)

func gracefulShutdown(apiServer *http.Server, serverInstance *server.Server, done chan bool) {
	// Create context that listens for the interrupt signal from the OS.
	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	// Listen for the interrupt signal.
	<-ctx.Done()

	log.Println("shutting down gracefully, press Ctrl+C again to force")
	stop() // Allow Ctrl+C to force shutdown

	// The context is used to inform the server it has 5 seconds to finish
	// the request it is currently handling
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := apiServer.Shutdown(ctx); err != nil {
		log.Printf("Server forced to shutdown with error: %v", err)
	}

	// Close database connection
	if serverInstance != nil && serverInstance.DB() != nil {
		serverInstance.DB().Close()
		log.Println("Database connection closed")
	}

	log.Println("Server exiting")

	// Notify the main goroutine that the shutdown is complete
	done <- true
}

func main() {
	if err := godotenv.Load(); err != nil {
		log.Println("No .env file found, using defaults")
	}

	// Define flags
	seed := flag.Bool("seed", false, "seed the database with fruit data")
	flag.Parse()

	httpServer, serverInstance := server.NewServer()

	// Handle seeding if flag is set
	if *seed {
		ctx := context.Background()
		log.Println("Running migrations...")
		if err := serverInstance.Repo.Migrate(ctx); err != nil {
			log.Fatalf("Migration failed: %v", err)
		}

		log.Println("Seeding database...")
		if err := serverInstance.FruitSvc.Seed(ctx); err != nil {
			log.Fatalf("Seeding failed: %v", err)
		}
		log.Println("Seeding complete.")

		// If you want it to exit after seeding, uncomment the next line
		// os.Exit(0)
	}

	// Create a done channel to signal when the shutdown is complete
	done := make(chan bool, 1)

	// Run graceful shutdown in a separate goroutine
	go gracefulShutdown(httpServer, serverInstance, done)

	fmt.Printf("Server starting on http://localhost%s\n", httpServer.Addr)
	fmt.Printf("Example query: http://localhost%s/search?q=sweet+yellow+fruit\n", httpServer.Addr)

	err := httpServer.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		panic(fmt.Sprintf("http server error: %s", err))
	}

	// Wait for the graceful shutdown to complete
	<-done
	log.Println("Graceful shutdown complete.")
}

package server

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"vector-search-project/internal/controller"
	"vector-search-project/internal/database"
	"vector-search-project/internal/repository"
	"vector-search-project/internal/service"
)

type Server struct {
	port int
	db   database.Service
}

func NewServer() *http.Server {
	portStr := os.Getenv("PORT")
	if portStr == "" {
		portStr = "8080"
	}
	port := 8080
	fmt.Sscanf(portStr, "%d", &port)

	db := database.New()

	newServer := &Server{
		port: port,
		db:   db,
	}

	ctx := context.Background()

	// Initialize repositories and services
	fruitRepo := repository.NewFruitRepository(db.Pool())
	embedSvc := service.NewEmbeddingService()
	fruitSvc := service.NewFruitService(fruitRepo, embedSvc)
	fruitCtrl := controller.NewFruitController(fruitSvc)

	// Run migrations and seed data
	if err := fruitRepo.Migrate(ctx); err != nil {
		log.Printf("migration failed: %v", err)
	}
	if err := fruitSvc.Seed(ctx); err != nil {
		log.Printf("seeding failed: %v", err)
	}

	// Declare Server config
	server := &http.Server{
		Addr:         fmt.Sprintf(":%d", newServer.port),
		Handler:      newServer.RegisterRoutes(fruitCtrl),
		IdleTimeout:  time.Minute,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	return server
}

package server

import (
	"fmt"
	"net/http"
	"os"
	"time"

	"vector-search-project/internal/controller"
	"vector-search-project/internal/database"
	"vector-search-project/internal/repository"
	"vector-search-project/internal/service"
)

type Server struct {
	port     int
	db       database.Service
	FruitSvc service.FruitService
	Repo     repository.FruitRepository
}

func (s *Server) DB() database.Service {
	return s.db
}

func NewServer() (*http.Server, *Server) {
	portStr := os.Getenv("PORT")
	if portStr == "" {
		portStr = "8080"
	}
	port := 8080
	fmt.Sscanf(portStr, "%d", &port)

	db := database.New()

	newServer := &Server{
		port: port,
		db:   db,
	}

	// Initialize repositories and services
	fruitRepo := repository.NewFruitRepository(db.Pool())
	embedSvc := service.NewEmbeddingService()
	fruitSvc := service.NewFruitService(fruitRepo, embedSvc)
	fruitCtrl := controller.NewFruitController(fruitSvc)

	newServer.FruitSvc = fruitSvc
	newServer.Repo = fruitRepo

	// Declare Server config
	server := &http.Server{
		Addr:         fmt.Sprintf(":%d", newServer.port),
		Handler:      newServer.RegisterRoutes(fruitCtrl),
		IdleTimeout:  time.Minute,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	return server, newServer
}
